package main

import (
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/scene3d"
)

func (w *World) buildLevel() {
	w.buildPrimitiveLevel()
}

func (w *World) spawnStaticBox(position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	return w.scene.Spawn(scene3d.EntityDesc{Position: position, Rotation: rotation, Scale: scale, Model: w.cubeModel, Tint: tint, TintSet: true, Tag: tag, Physics: boxPhysics(scale)})
}

func (w *World) spawnStaticModel(model voplay.ModelID, position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	physics := scene3d.TrimeshPhysics(model)
	physics.Friction = 0.9
	return w.scene.Spawn(scene3d.EntityDesc{Position: position, Rotation: rotation, Scale: scale, Model: model, Tint: tint, TintSet: true, Tag: tag, Physics: physics})
}

func boxPhysics(scale voplay.Vec3) *scene3d.Physics {
	return &scene3d.Physics{Type: scene3d.Static, Collider: scene3d.Box(scale.X * 0.5, scale.Y * 0.5, scale.Z * 0.5), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll, Friction: 0.72, Restitution: 0.02}
}

func (w *World) spawnVisualBox(position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	return w.spawnVisualModel(w.cubeModel, position, rotation, scale, tint, tag)
}

func (w *World) spawnVisualCylinder(position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	return w.spawnVisualModel(w.cylinderModel, position, rotation, scale, tint, tag)
}

func (w *World) spawnVisualModel(model voplay.ModelID, position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	return w.scene.Spawn(scene3d.EntityDesc{Position: position, Rotation: rotation, Scale: scale, Model: model, Tint: tint, TintSet: true, Tag: tag})
}

func (w *World) spawnDecoSphere(position, scale voplay.Vec3, tint voplay.Color, tag string) *scene3d.Entity {
	return w.spawnVisualModel(w.sphereModel, position, voplay.QuatIdentity(), scale, tint, tag)
}

package main

import (
	"math"
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/scene3d"
)

const (
	collectibleRadius = 3.35
	checkpointRadius = 14.0
)

type Collectible struct {
	Core *scene3d.Entity
	Glow *scene3d.Entity
	CorePrimitive *PrimitivePart
	GlowPrimitive *PrimitivePart
	Position voplay.Vec3
	Collected bool
}

type Checkpoint struct {
	Position voplay.Vec3
	Respawn voplay.Vec3
	Yaw float64
	Label string
	Radius float64
	Reached bool
}

type BoostPad struct {
	Position voplay.Vec3
	Radius float64
}

type MovingObstacle struct {
	Entity *scene3d.Entity
	Visual *PrimitivePart
	Origin voplay.Vec3
	Axis voplay.Vec3
	Amplitude float64
	Speed float64
	Phase float64
}

func (w *World) addCollectible(position voplay.Vec3, tag string) {
	primitive := w.ensurePrimitiveScene()
	core := primitive.AddDynamic(primitive.RoundedBox, primitive.OrbMat, position, voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, 0.78), voplay.Vec3{X: 1.15, Y: 1.15, Z: 1.15}, w.theme.OrbColor)
	glow := primitive.AddDynamic(primitive.Sphere, primitive.GlowMat, position.Add(voplay.Vec3{Y: -0.12}), voplay.QuatIdentity(), voplay.Vec3{X: 1.55, Y: 0.3, Z: 1.55}, w.theme.GoalTrimColor)
	w.collectibles = append(w.collectibles, &Collectible{CorePrimitive: core, GlowPrimitive: glow, Position: position})
}

func (w *World) addCollectibleLine(start, end voplay.Vec3, count int, tag string) {
	if count <= 1 {
		w.addCollectible(start, tag + "_0")
		return
	}
	for i := 0; i < count; i++ {
		t := float64(i) / float64(count - 1)
		w.addCollectible(start.Lerp(end, t), tag + "_" + itoa(i))
	}
}

func (w *World) addCheckpoint(position, respawn voplay.Vec3, yaw float64, label string) {
	w.checkpoints = append(w.checkpoints, &Checkpoint{Position: position, Respawn: respawn, Yaw: yaw, Label: label, Radius: checkpointRadius})
}

func (w *World) addBoostPad(position voplay.Vec3, radius float64) {
	w.boostPads = append(w.boostPads, &BoostPad{Position: position, Radius: radius})
}

func (w *World) addMovingObstacle(position, scale, axis voplay.Vec3, amplitude, speed, phase float64, tag string) {
	entity := w.scene.Spawn(scene3d.EntityDesc{Position: position, Rotation: voplay.QuatIdentity(), Scale: voplay.Vec3{X: 1, Y: 1, Z: 1}, Tag: tag + "_physics", Physics: boxPhysics(scale), PickMode: scene3d.PickDisabled})
	entity.Visible = false
	primitive := w.ensurePrimitiveScene()
	visual := primitive.AddDynamic(primitive.RoundedBox, primitive.HazardMat, position, voplay.QuatIdentity(), scale, w.theme.HazardColor)
	w.obstacles = append(w.obstacles, &MovingObstacle{Entity: entity, Visual: visual, Origin: position, Axis: axis.Normalize(), Amplitude: amplitude, Speed: speed, Phase: phase})
}

func (w *World) updateGameplay(dt float64) {
	if !w.finished {
		w.courseTime += dt
	}
	w.messageTimer = maxFloat(0, w.messageTimer - dt)
	w.updateMovingObstacles()
	w.updateCollectibles()
	w.updateBoostPads()
	w.updateRaceProgress()
	w.boostTimer = maxFloat(0, w.boostTimer - dt)
}

func (w *World) updateMovingObstacles() {
	for _, obstacle := range w.obstacles {
		if obstacle == nil || obstacle.Entity == nil {
			continue
		}
		offset := math.Sin(w.courseTime * obstacle.Speed + obstacle.Phase) * obstacle.Amplitude
		position := obstacle.Origin.Add(obstacle.Axis.Scale(offset))
		obstacle.Entity.SetPosition(position)
		if obstacle.Visual != nil {
			obstacle.Visual.SetPose(position, voplay.QuatIdentity())
		}
	}
}

func (w *World) updateCollectibles() {
	if w.player == nil {
		return
	}
	playerPos := w.player.Position()
	for _, item := range w.collectibles {
		if item == nil || item.Collected {
			continue
		}
		if playerPos.Distance(item.Position) > collectibleRadius {
			continue
		}
		item.Collected = true
		w.collected++
		w.activateBoost(kartItemBoostDuration)
		w.message = "Item boost!"
		w.messageTimer = 1.1
		hideEntity(item.Core)
		hideEntity(item.Glow)
		hidePrimitivePart(item.CorePrimitive)
		hidePrimitivePart(item.GlowPrimitive)
	}
}

func (w *World) updateBoostPads() {
	if w.player == nil {
		return
	}
	playerPos := w.player.Position()
	for _, pad := range w.boostPads {
		if pad == nil {
			continue
		}
		if playerPos.Distance(pad.Position) > pad.Radius {
			continue
		}
		if w.boostTimer < 0.25 {
			w.message = "Boost pad!"
			w.messageTimer = 0.8
		}
		w.activateBoost(kartBoostPadDuration)
	}
}

func (w *World) updateRaceProgress() {
	if w.finished || w.player == nil || len(w.checkpoints) == 0 {
		return
	}
	if w.nextCheckpoint < 0 || w.nextCheckpoint >= len(w.checkpoints) {
		w.nextCheckpoint = 0
	}
	checkpoint := w.checkpoints[w.nextCheckpoint]
	if checkpoint == nil {
		return
	}
	if w.player.Position().Distance(checkpoint.Position) > checkpoint.Radius {
		return
	}
	checkpoint.Reached = true
	w.checkpointPosition = checkpoint.Respawn
	w.checkpointYaw = checkpoint.Yaw
	w.checkpointLabel = checkpoint.Label
	if w.nextCheckpoint == len(w.checkpoints) - 1 {
		if w.lap >= w.totalLaps {
			w.finished = true
			w.finishTime = w.courseTime
			w.nextGateLabel = "Done"
			w.message = "Race complete!"
			w.messageTimer = 99
			w.player.SetVelocity(voplay.Vec3{})
			if w.vehicle != nil {
				w.vehicle.Speed = 0
			}
			w.kartSpeed = 0
			return
		}
		w.lap++
		w.nextCheckpoint = 0
		w.refreshNextGateLabel()
		for _, gate := range w.checkpoints {
			if gate != nil {
				gate.Reached = false
			}
		}
		w.message = "Lap " + itoa(w.lap) + "/" + itoa(w.totalLaps)
		w.messageTimer = 1.3
		return
	}
	w.nextCheckpoint++
	w.refreshNextGateLabel()
	w.message = "Gate: " + checkpoint.Label
	w.messageTimer = 1.0
}

func (w *World) refreshNextGateLabel() {
	if len(w.checkpoints) == 0 {
		w.nextGateLabel = "Start"
		return
	}
	if w.nextCheckpoint < 0 || w.nextCheckpoint >= len(w.checkpoints) {
		w.nextCheckpoint = 0
	}
	checkpoint := w.checkpoints[w.nextCheckpoint]
	if checkpoint == nil {
		w.nextGateLabel = "Gate"
		return
	}
	w.nextGateLabel = checkpoint.Label
}

func (w *World) respawnAtCheckpoint() {
	w.setKartPose(w.checkpointPosition, w.checkpointYaw)
	w.updateRacingCamera(0)
	w.message = "Back to " + w.checkpointLabel
	w.messageTimer = 1.2
}

func (w *World) restartRun() {
	w.courseTime = 0
	w.finishTime = 0
	w.finished = false
	w.collected = 0
	w.lap = 1
	if w.totalLaps <= 0 {
		w.totalLaps = raceLapCount
	}
	w.nextCheckpoint = 0
	w.kartSpeed = 0
	w.kartYaw = w.startYaw
	if w.vehicle != nil {
		w.vehicle.Speed = 0
		w.vehicle.Yaw = w.startYaw
	}
	w.boostTimer = 0
	w.driftCharge = 0
	w.drifting = false
	w.wasDrifting = false
	w.checkpointPosition = w.startPosition
	w.checkpointYaw = w.startYaw
	w.checkpointLabel = "Start"
	w.refreshNextGateLabel()
	for _, checkpoint := range w.checkpoints {
		if checkpoint != nil {
			checkpoint.Reached = false
		}
	}
	for _, item := range w.collectibles {
		if item == nil {
			continue
		}
		item.Collected = false
		showEntity(item.Core)
		showEntity(item.Glow)
		showPrimitivePart(item.CorePrimitive)
		showPrimitivePart(item.GlowPrimitive)
	}
	w.respawnAtCheckpoint()
	w.message = "Go!"
	w.messageTimer = 1.1
}

func hideEntity(e *scene3d.Entity) {
	if e != nil {
		e.Visible = false
	}
}

func showEntity(e *scene3d.Entity) {
	if e != nil {
		e.Visible = true
	}
}

func maxFloat(a, b float64) float64 {
	if a > b {
		return a
	}
	return b
}

func itoa(value int) string {
	digits := "0123456789"
	if value == 0 {
		return "0"
	}
	out := ""
	n := value
	for n > 0 {
		d := n % 10
		out = digits[d:d + 1] + out
		n = n / 10
	}
	return out
}

