package main

import (
	"errors"
	"path/filepath"
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/scene3d"
)

const (
	defaultTrackPackPath = "maps/scenic_track/track.json"
	defaultTrackFilePath = "assets/maps/scenic_track/track.json"
	fallbackTrackPackPath = "maps/demo_track/track.json"
	fallbackTrackFilePath = "assets/maps/demo_track/track.json"
	trackAssetGroup = "blockkart-track"
)

func (w *World) loadDemoTrack() {
	result, err := w.loadDemoTrackFromAssets()
	if err != nil && result == nil {
		result, err = w.loadDemoTrackFromFiles()
	}
	if err != nil {
		w.message = "Track load failed: " + err.Error()
		w.messageTimer = 4
		return
	}
	w.trackResult = result
	w.track = result.Track
	w.applyDemoTrackSpawn(result)
	w.populateTrackCheckpoints(result.Track)
}

func (w *World) loadDemoTrackFromAssets() (*scene3d.TrackSpawnResult, error) {
	if w.assets == nil || w.assetPackPath == "" {
		if w.assets == nil {
			return nil, errTrackAssetsUnavailable()
		}
	}
	w.assets.BeginGroup(trackAssetGroup)
	var result *scene3d.TrackSpawnResult
	var err error
	var lastPath string
	for _, path := range demoTrackAssetCandidates(w.assetPackPath != "") {
		lastPath = path
		result, err = scene3d.LoadTrackWithAssets(w.scene, w.assets, path)
		if err == nil && trackSpawnHasVisuals(result) {
			break
		}
		if err == nil {
			err = errors.New("track loaded without visual entities: " + path)
		}
	}
	w.assets.EndGroup()
	if err != nil {
		w.assets.ReleaseGroup(trackAssetGroup)
		return nil, err
	}
	if !trackSpawnHasVisuals(result) {
		w.assets.ReleaseGroup(trackAssetGroup)
		return nil, errors.New("track loaded without visual entities: " + lastPath)
	}
	w.trackAssetGroup = trackAssetGroup
	return result, nil
}

func (w *World) loadDemoTrackFromFiles() (*scene3d.TrackSpawnResult, error) {
	var lastErr error
	for _, path := range demoTrackFileCandidates() {
		result, err := scene3d.LoadTrack(w.scene, path)
		if err == nil {
			return result, nil
		}
		lastErr = err
	}
	return nil, lastErr
}

func (w *World) applyDemoTrackSpawn(result *scene3d.TrackSpawnResult) {
	if result == nil || result.Track == nil || result.Track.Asset() == nil {
		return
	}
	for _, spawn := range result.Track.Asset().Spawns {
		if spawn.Name != "player_start" {
			continue
		}
		pose := result.Track.PoseAt(spawn.Distance)
		if spawn.Position != (scene3d.MapVec3{}) {
			pose.Position = spawn.Position.Vec3()
		}
		if spawn.Yaw != 0 {
			pose.Yaw = spawn.Yaw
		}
		w.startPosition = kartTrackRidePosition(pose.Position)
		w.startYaw = pose.Yaw
		w.checkpointPosition = w.startPosition
		w.checkpointYaw = w.startYaw
		w.kartYaw = w.startYaw
		return
	}
}

func (w *World) populateTrackCheckpoints(track *scene3d.Track) {
	if track == nil || track.Asset() == nil {
		return
	}
	w.checkpoints = nil
	for _, gate := range track.Asset().Gates {
		pose := track.PoseAt(gate.Distance)
		respawn := track.RespawnPoseNear(pose.Position)
		radius := gate.Radius
		if radius <= 0 {
			radius = checkpointRadius
		}
		w.checkpoints = append(w.checkpoints, &Checkpoint{Position: kartTrackRidePosition(pose.Position), Respawn: kartTrackRidePosition(respawn.Position), Yaw: respawn.Yaw, Label: gate.Name, Radius: radius})
	}
	w.refreshNextGateLabel()
}

func kartTrackRidePosition(position voplay.Vec3) voplay.Vec3 {
	return position.Add(voplay.Vec3{Y: kartSpawnRideHeight})
}

func demoTrackFileCandidates() []string {
	paths := []string{}
	for _, root := range assetRootCandidates() {
		paths = appendDemoTrackPath(paths, filepath.Join([]string{root, "maps", "scenic_track", "track.json"}))
		paths = appendDemoTrackPath(paths, filepath.Join([]string{root, "maps", "demo_track", "track.json"}))
	}
	paths = appendDemoTrackPath(paths, defaultTrackFilePath)
	paths = appendDemoTrackPath(paths, fallbackTrackFilePath)
	return paths
}

func demoTrackAssetCandidates(hasPack bool) []string {
	paths := []string{}
	if hasPack {
		paths = appendDemoTrackPath(paths, defaultTrackPackPath)
		paths = appendDemoTrackPath(paths, fallbackTrackPackPath)
	}
	paths = appendDemoTrackPath(paths, defaultTrackFilePath)
	paths = appendDemoTrackPath(paths, fallbackTrackFilePath)
	return paths
}

func trackSpawnHasVisuals(result *scene3d.TrackSpawnResult) bool {
	return result != nil && len(result.Entities) > 0
}

func appendDemoTrackPath(paths []string, path string) []string {
	if path == "" {
		return paths
	}
	for _, existing := range paths {
		if existing == path {
			return paths
		}
	}
	return append(paths, path)
}

func errTrackAssetsUnavailable() error {
	return errors.New("track assets unavailable")
}

package main

import (
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/scene3d"
)

type PlayState struct {
	world *World
	elapsed float64
	debugOverlayVisible bool
	renderDebugMode int
	heroCameraVisible bool
}

func NewPlayState() *PlayState {
	return &PlayState{}
}

func (s *PlayState) Enter(g *voplay.GameCtx) {
	s.elapsed = 0
	bindGameActions(g)
	s.world = NewWorld(g)
	s.applyDebugOverlay(g)
	if s.world != nil {
		s.world.SetRenderDebugMode(s.renderDebugMode)
		s.world.SetHeroCameraVisible(s.heroCameraVisible)
	}
}

func (s *PlayState) Exit(g *voplay.GameCtx) {
	g.HideDebugOverlay()
	if s.world != nil {
		s.world.Close()
		s.world = nil
	}
}

func (s *PlayState) FixedUpdate(g *voplay.GameCtx, dt float64) {
	s.elapsed += dt
	if s.world == nil {
		return
	}
	s.world.FixedUpdate(g, dt)
}

func (s *PlayState) Update(g *voplay.GameCtx, dt float64) {
	if g.Actions.IsPressed("toggle_debug_overlay") {
		s.debugOverlayVisible = !s.debugOverlayVisible
		s.applyDebugOverlay(g)
	}
	if g.Actions.IsPressed("cycle_render_debug") {
		s.renderDebugMode++
		if s.renderDebugMode > scene3d.RenderDebugAmbient {
			s.renderDebugMode = scene3d.RenderDebugLit
		}
		if s.world != nil {
			s.world.SetRenderDebugMode(s.renderDebugMode)
		}
	}
	if g.Actions.IsPressed("toggle_hero_camera") {
		s.heroCameraVisible = !s.heroCameraVisible
		if s.world != nil {
			s.world.SetHeroCameraVisible(s.heroCameraVisible)
		}
	}
	if s.world == nil {
		return
	}
	s.world.Update(g, dt)
}

func (s *PlayState) Draw(g *voplay.GameCtx) {
	clearColor := defaultWorldTheme().SkyColor
	if s.world != nil {
		clearColor = s.world.theme.SkyColor
	}
	g.Draw.ClearColor(clearColor)
	if s.world != nil {
		s.world.Draw(g, s.debugOverlayVisible)
	}
}

func (s *PlayState) applyDebugOverlay(g *voplay.GameCtx) {
	if s.debugOverlayVisible {
		g.ShowDebugOverlay()
		return
	}
	g.HideDebugOverlay()
}

func bindGameActions(g *voplay.GameCtx) {
	g.Actions.Rebind("reset", voplay.KeyBinding("r"))
	g.Actions.Rebind("toggle_debug_overlay", voplay.KeyBinding("F3"))
	g.Actions.Rebind("cycle_render_debug", voplay.KeyBinding("F4"))
	g.Actions.Rebind("toggle_hero_camera", voplay.KeyBinding("F5"))
}

package main

import (
	"math"
	"path/filepath"
	"strconv"
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/primitive3d"
	"github.com/vo-lang/voplay/scene3d"
)

const (
	primitiveTrackWidth = 17.5
	primitiveTrackSegmentLength = 5.8
	primitiveKartVisualScale = 1.72
	primitiveMapPlanarScale = 2.45
	primitiveTerrainWidth = 882.0
	primitiveTerrainDepth = 882.0
	primitiveTerrainY = -2.6
	primitiveTerrainHeight = 12.0
	primitiveLandmarkScale = 1.42
	primitiveStaticBatchCellSize = 0.0
)

type BlockKartPrimitiveScene struct {
	Shapes *primitive3d.ShapeRegistry
	Materials *primitive3d.MaterialPalette
	Static *primitive3d.Layer
	Dynamic *primitive3d.Layer
	Box primitive3d.ShapeID
	RoundedBox primitive3d.ShapeID
	Sphere primitive3d.ShapeID
	Cylinder primitive3d.ShapeID
	Cone primitive3d.ShapeID
	Wedge primitive3d.ShapeID
	RoadMat primitive3d.MaterialID
	RoadStripeMat primitive3d.MaterialID
	CurbRedMat primitive3d.MaterialID
	CurbCreamMat primitive3d.MaterialID
	GrassMat primitive3d.MaterialID
	MeadowMat primitive3d.MaterialID
	StoneMat primitive3d.MaterialID
	CliffMat primitive3d.MaterialID
	PaleStoneMat primitive3d.MaterialID
	WoodMat primitive3d.MaterialID
	LeafMat primitive3d.MaterialID
	BushMat primitive3d.MaterialID
	WaterMat primitive3d.MaterialID
	SignMat primitive3d.MaterialID
	SignArrowMat primitive3d.MaterialID
	PlayerMat primitive3d.MaterialID
	TrimMat primitive3d.MaterialID
	OrangeTrimMat primitive3d.MaterialID
	WhiteMat primitive3d.MaterialID
	TopBlueMat primitive3d.MaterialID
	VisorMat primitive3d.MaterialID
	DriverMat primitive3d.MaterialID
	WheelMat primitive3d.MaterialID
	MetalMat primitive3d.MaterialID
	BoostMat primitive3d.MaterialID
	GlowMat primitive3d.MaterialID
	OrbMat primitive3d.MaterialID
	HazardMat primitive3d.MaterialID
	CloudMat primitive3d.MaterialID
	CloudShadowMat primitive3d.MaterialID
	TowerWallMat primitive3d.MaterialID
	TowerRoofMat primitive3d.MaterialID
