}

type PrimitiveRoadVertex struct {
	Position voplay.Vec3
	Normal voplay.Vec3
	U float64
	V float64
}

type primitiveRoadWriter struct {
	buf []byte
}

func (w *World) ensurePrimitiveScene() *BlockKartPrimitiveScene {
	if w.primitive != nil {
		return w.primitive
	}
	w.primitive = newBlockKartPrimitiveScene(w.scene)
	return w.primitive
}

func newBlockKartPrimitiveScene(scene *scene3d.Scene) *BlockKartPrimitiveScene {
	shapes := primitive3d.NewShapeRegistry()
	materials := primitive3d.NewMaterialPalette()
	staticLayer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.StaticLayer, Shapes: shapes, Materials: materials, Chunking: primitive3d.ChunkingDesc{CellSize: primitiveStaticBatchCellSize}, Name: "blockkart_static_primitives"})
	dynamicLayer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.DynamicLayer, Shapes: shapes, Materials: materials, Name: "blockkart_dynamic_primitives"})
