func (p *BlockKartPrimitiveScene) material(preset primitive3d.MaterialPreset, color voplay.Color, roughness, metallic float64, emissive voplay.Color) primitive3d.MaterialID {
	base := voplay.MaterialDesc{BaseColor: color, Roughness: roughness, Metallic: metallic, UVScale: 1}
	if emissive != (voplay.Color{}) {
		base.EmissiveColor = emissive
	}
	return p.Materials.Material(primitive3d.MaterialDesc{Preset: preset, Base: base})
}

func (p *BlockKartPrimitiveScene) AddStatic(shape primitive3d.ShapeID, material primitive3d.MaterialID, position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color) primitive3d.ObjectID {
	return p.Static.Add(primitive3d.Instance{Shape: shape, Material: material, Position: position, Rotation: normalizePrimitiveQuat(rotation), Scale: normalizePrimitiveVecScale(scale), Tint: tint})
}

func (p *BlockKartPrimitiveScene) AddDynamic(shape primitive3d.ShapeID, material primitive3d.MaterialID, position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3, tint voplay.Color) *PrimitivePart {
	instance := primitive3d.Instance{Shape: shape, Material: material, Position: position, Rotation: normalizePrimitiveQuat(rotation), Scale: normalizePrimitiveVecScale(scale), Tint: tint}
	id := p.Dynamic.Add(instance)
	return &PrimitivePart{Layer: p.Dynamic, Object: id, Shape: shape, Material: material, Position: position, Rotation: normalizePrimitiveQuat(rotation), Scale: normalizePrimitiveVecScale(scale), Tint: tint, Visible: true}
}

func (p *PrimitivePart) SetPose(position voplay.Vec3, rotation voplay.Quat) {
	if p == nil || p.Layer == nil || p.Object == 0 {
		return
	}
	p.Position = position
	p.Rotation = normalizePrimitiveQuat(rotation)
	p.write()
}

func (p *PrimitivePart) SetPoseScale(position voplay.Vec3, rotation voplay.Quat, scale voplay.Vec3) {
	if p == nil {
		return
	}
	p.Scale = normalizePrimitiveVecScale(scale)
	p.SetPose(position, rotation)
}

func (p *PrimitivePart) SetVisible(visible bool) {
	if p == nil || p.Layer == nil || p.Object == 0 {
		return
	}
	p.Visible = visible
	p.write()
}

func (p *PrimitivePart) write() {
	if p == nil || p.Layer == nil || p.Object == 0 {
		return
	}
	scale := p.Scale
	if !p.Visible {
		scale = voplay.Vec3{X: 0.001, Y: 0.001, Z: 0.001}
	}
	p.Layer.Set(p.Object, primitive3d.Instance{Shape: p.Shape, Material: p.Material, Position: p.Position, Rotation: normalizePrimitiveQuat(p.Rotation), Scale: normalizePrimitiveVecScale(scale), Tint: p.Tint, Object: p.Object})
}

func hidePrimitivePart(part *PrimitivePart) {
	if part != nil {
		part.SetVisible(false)
	}
}

func showPrimitivePart(part *PrimitivePart) {
	if part != nil {
		part.SetVisible(true)
	}
}

func (w *World) buildPrimitiveLevel() {
	primitive := w.ensurePrimitiveScene()
	asset := newPrimitiveTrackAsset()
	track, err := scene3d.NewTrack(asset)
	if err != nil {
		w.message = "Primitive track failed: " + err.Error()
		w.messageTimer = 4
		return
	}
	w.track = track
	result, terrainErr := w.spawnPrimitiveTrackTerrain(track)
	if terrainErr != nil {
		w.message = "Terrain failed: " + terrainErr.Error()
		w.messageTimer = 4
	}
	w.trackResult = result
	w.applyDemoTrackSpawn(w.trackResult)
	w.populateTrackCheckpoints(track)
	w.buildPrimitiveTrackVisuals(track)
	w.spawnPrimitiveTrackPhysics(track)
	w.spawnPrimitiveGameplay(track)
	primitive.Static.Build()
}

func newPrimitiveTrackAsset() *scene3d.TrackAsset {
	points := primitiveTrackControlPoints()
	length := primitiveTrackLength(points)
	start := length * 0.44
	return &scene3d.TrackAsset{Version: 1, Name: "primitive_block_kart", ClosedLoop: true, Terrain: primitiveTrackTerrainAsset(), Centerline: points, Surfaces: []scene3d.TrackSurface{{Name: "primitive_road", Kind: scene3d.TrackSurfaceRoad, Start: 0, End: 0, Friction: 1.05}, {Name: "primitive_boost_1", Kind: scene3d.TrackSurfaceBoost, Start: length * 0.12, End: length * 0.15, Left: -4.2, Right: 4.2, Priority: 4, Friction: 1.08, Boost: 1.0}, {Name: "primitive_boost_2", Kind: scene3d.TrackSurfaceBoost, Start: length * 0.58, End: length * 0.61, Left: -4.2, Right: 4.2, Priority: 4, Friction: 1.08, Boost: 1.0}}, Gates: []scene3d.TrackGate{{Name: "Gate 1", Distance: start, Width: primitiveTrackWidth, Radius: 15}, {Name: "Gate 2", Distance: length * 0.58, Width: primitiveTrackWidth, Radius: 15}, {Name: "Gate 3", Distance: length * 0.72, Width: primitiveTrackWidth, Radius: 15}, {Name: "Gate 4", Distance: length * 0.86, Width: primitiveTrackWidth, Radius: 15}}, Spawns: []scene3d.TrackSpawn{{Name: "player_start", Distance: start}}, Respawns: []scene3d.TrackRespawn{{Name: "respawn_start", Distance: start}, {Name: "respawn_2", Distance: length * 0.58}, {Name: "respawn_3", Distance: length * 0.72}, {Name: "respawn_4", Distance: length * 0.86}}}
}

func (w *World) spawnPrimitiveTrackTerrain(track *scene3d.Track) (*scene3d.TrackSpawnResult, error) {
	fallback := &scene3d.TrackSpawnResult{Track: track, Entities: []*scene3d.Entity{}, Meshes: map[string]*scene3d.Entity{}, CollisionMeshes: map[string]*scene3d.Entity{}, Textures: []voplay.TextureID{}}
	if w.assets == nil {
		return fallback, nil
	}
	var lastErr error
	for _, baseDir := range primitiveTrackTerrainBaseDirs() {
		w.assets.BeginGroup(worldAssetGroup)
		result, err := scene3d.SpawnTrackWithAssets(w.scene, w.assets, track, baseDir)
		w.assets.EndGroup()
		if err == nil {
			return result, nil
		}
		lastErr = err
	}
	if lastErr != nil {
		return fallback, lastErr
	}
	return fallback, nil
}

func primitiveTrackTerrainAsset() *scene3d.MapTerrain {
	return &scene3d.MapTerrain{Tag: "primitive_heightmap_terrain", Heightmap: "heightmap_large.png", Position: scene3d.MapVec3{Y: primitiveTerrainY}, Width: primitiveTerrainWidth, Height: primitiveTerrainHeight, Depth: primitiveTerrainDepth, Splat: &scene3d.MapTerrainSplat{Control: "terrain_splat_large.png", Layers: []scene3d.MapTerrainSplatLayer{{Texture: "../scenic_track/grass_texture.png", Normal: "../scenic_track/grass_normal.png", MetallicRoughness: "../scenic_track/grass_mr.png", UVScale: 84, NormalScale: 0.46}, {Texture: "../scenic_track/meadow_texture.png", Normal: "../scenic_track/meadow_normal.png", MetallicRoughness: "../scenic_track/meadow_mr.png", UVScale: 74, NormalScale: 0.46}, {Texture: "../scenic_track/dirt_texture.png", Normal: "../scenic_track/dirt_normal.png", MetallicRoughness: "../scenic_track/dirt_mr.png", UVScale: 60, NormalScale: 0.58}, {Texture: "../scenic_track/rock_texture.png", Normal: "../scenic_track/rock_normal.png", MetallicRoughness: "../scenic_track/rock_mr.png", UVScale: 44, NormalScale: 0.72}}}, TintSet: true, Tint: scene3d.MapColor{R: 0.78, G: 0.9, B: 0.7, A: 1}, Friction: 0.88}
}

func primitiveTrackTerrainBaseDirs() []string {
	dirs := []string{}
	for _, root := range assetRootCandidates() {
		dirs = appendPrimitiveTerrainBaseDir(dirs, filepath.Join([]string{root, "maps", "primitive_track"}))
	}
	return dirs
}

func appendPrimitiveTerrainBaseDir(dirs []string, dir string) []string {
	if dir == "" {
		return dirs
	}
	for _, existing := range dirs {
		if existing == dir {
			return dirs
		}
	}
	return append(dirs, dir)
}

func primitiveTrackControlPoints() []scene3d.TrackControlPoint {
	points := []scene3d.TrackControlPoint{}
	count := 24
	for i := 0; i <= count; i++ {
		t := float64(i) / float64(count)
		a := t * math.Pi * 2
		rx := primitiveMapPlanarScale * (86.0 + 12.0 * math.Sin(a * 3.0 + 0.35))
		rz := primitiveMapPlanarScale * (66.0 + 9.0 * math.Cos(a * 2.0 - 0.2))
		position := voplay.Vec3{X: math.Sin(a) * rx, Y: 0.45 * math.Sin(a * 2.0 + 0.4), Z: math.Cos(a) * rz}
		width := primitiveTrackWidth + 1.6 * math.Sin(a * 2.0)
		points = append(points, scene3d.TrackControlPoint{Position: primitiveMapVec3(position), Width: width})
	}
	primitiveStraightenSpawnRun(points)
	return points
}

func primitiveStraightenSpawnRun(points []scene3d.TrackControlPoint) {
	if len(points) < 13 {
		return
	}
	entry := points[10].Position.Vec3()
	anchor := points[11].Position.Vec3()
	forward := anchor.Sub(entry).Normalize()
	if forward.LengthSq() == 0 {
		return
	}
	points[12].Position = primitiveMapVec3(anchor.Add(forward.Scale(62.0)))
	points[12].Width = primitiveTrackWidth + 0.8
}

func primitiveTrackLength(points []scene3d.TrackControlPoint) float64 {
	total := 0.0
	for i := 0; i < len(points) - 1; i++ {
		total += points[i].Position.Vec3().Distance(points[i + 1].Position.Vec3())
	}
	return total
}

func primitiveMapVec3(v voplay.Vec3) scene3d.MapVec3 {
	return scene3d.MapVec3{X: v.X, Y: v.Y, Z: v.Z}
}

func primitiveSceneryVec3(x, y, z float64) voplay.Vec3 {
	return voplay.Vec3{X: x * primitiveMapPlanarScale, Y: y, Z: z * primitiveMapPlanarScale}
}

func primitiveLandmarkVec3(x, y, z float64) voplay.Vec3 {
	return voplay.Vec3{X: x * primitiveLandmarkScale, Y: y * primitiveLandmarkScale, Z: z * primitiveLandmarkScale}
}

func (w *World) buildPrimitiveTrackVisuals(track *scene3d.Track) {
	primitive := w.ensurePrimitiveScene()
	w.addPrimitiveLandmarks(track)
	w.addContinuousPrimitiveRoadVisuals(track)
	count := primitiveTrackSampleCount(track)
	length := track.Length()
	step := length / float64(count)
	for i := 0; i < count; i++ {
		distance := float64(i) * step + step * 0.5
		pose := track.PoseAt(distance)
		curbMat := primitive.CurbCreamMat
		if i % 2 == 0 {
			curbMat = primitive.CurbRedMat
		}
		edge := pose.HalfWidth + 0.58
		primitive.AddStatic(primitive.RoundedBox, curbMat, pose.Position.Add(pose.Right.Scale(edge)).Add(voplay.Vec3{Y: 0.29}), pose.Rotation, voplay.Vec3{X: 1.18, Y: 0.28, Z: step * 0.48}, voplay.Color{})
		primitive.AddStatic(primitive.RoundedBox, curbMat, pose.Position.Sub(pose.Right.Scale(edge)).Add(voplay.Vec3{Y: 0.29}), pose.Rotation, voplay.Vec3{X: 1.18, Y: 0.28, Z: step * 0.48}, voplay.Color{})
		if i % 4 == 0 {
			w.addPrimitiveFencePair(pose, step)
		}
		if i % 6 == 1 {
			w.addPrimitiveTreeAtPose(pose, pose.HalfWidth + 19.0 + float64((i * 7) % 9), 0.88 + float64(i % 5) * 0.08)
		}
		if i % 7 == 3 {
			w.addPrimitiveTreeAtPose(pose, -(pose.HalfWidth + 22.0 + float64((i * 5) % 11)), 0.78 + float64(i % 4) * 0.07)
		}
		if i % 5 == 2 {
			w.addPrimitiveBushClusterAtPose(pose, pose.HalfWidth + 8.4)
		}
		if i % 5 == 4 {
			w.addPrimitiveBushClusterAtPose(pose, -(pose.HalfWidth + 8.8))
		}
		if i % 10 == 4 {
			w.addPrimitiveSignAtPose(pose, pose.HalfWidth + 5.6)
		}
		if i % 8 == 2 {
			w.addPrimitiveRocksAtPose(pose, -(pose.HalfWidth + 12.5))
		}
	}
	w.addPrimitiveStartGantry(primitiveTrackStartPose(track))
	w.addPrimitiveClouds()
}

func primitiveTrackStartPose(track *scene3d.Track) scene3d.TrackPose {
	if track == nil || track.Asset() == nil {
		return scene3d.TrackPose{}
	}
	for _, spawn := range track.Asset().Spawns {
		if spawn.Name == "player_start" {
			return track.PoseAt(spawn.Distance)
		}
	}
	return track.PoseAt(0)
}

func (w *World) addContinuousPrimitiveRoadVisuals(track *scene3d.Track) {
	if track == nil {
		return
	}
	primitive := w.ensurePrimitiveScene()
	count := primitiveTrackSampleCount(track)
	length := track.Length()
	step := length / float64(count)
	for i := 0; i < count; i++ {
		distance := float64(i) * step + step * 0.5
		pose := track.PoseAt(distance)
		primitive.AddStatic(primitive.RoundedBox, primitive.RoadMat, pose.Position.Add(voplay.Vec3{Y: 0.11}), pose.Rotation, voplay.Vec3{X: pose.HalfWidth*2 + 0.82, Y: 0.12, Z: step * 0.58}, voplay.Color{})
		primitive.AddStatic(primitive.RoundedBox, primitive.RoadStripeMat, pose.Position.Add(voplay.Vec3{Y: 0.19}), pose.Rotation, voplay.Vec3{X: 0.30, Y: 0.035, Z: step * 0.34}, voplay.Color{})
		if i % 6 == 1 {
			primitive.AddStatic(primitive.RoundedBox, primitive.TrimMat, pose.Position.Add(voplay.Vec3{Y: 0.18}), pose.Rotation, voplay.Vec3{X: pose.HalfWidth*2 - 2.2, Y: 0.035, Z: 0.10}, voplay.Color{})
		}
	}
}

func primitiveRoadMaterial(color voplay.Color, roughness float64) voplay.MaterialDesc {
	return voplay.MaterialDesc{BaseColor: color, Roughness: roughness, Metallic: 0, UVScale: 1}
}

func buildPrimitiveTrackRibbonGLB(track *scene3d.Track, sampleCount int, expand, height float64, color voplay.Color, roughness float64, name string) []byte {
	vertices := []PrimitiveRoadVertex{}
	indices := []int{}
	length := track.Length()
	for i := 0; i <= sampleCount; i++ {
		d := float64(i) / float64(sampleCount) * length
		if i == sampleCount {
			d = 0
		}
		pose := track.PoseAt(d)
		halfWidth := pose.HalfWidth + expand
		left := pose.Position.Sub(pose.Right.Scale(halfWidth)).Add(voplay.Vec3{Y: height})
		right := pose.Position.Add(pose.Right.Scale(halfWidth)).Add(voplay.Vec3{Y: height})
		v := d / 18.0
		vertices = append(vertices, PrimitiveRoadVertex{Position: left, Normal: voplay.Vec3{Y: 1}, U: 0, V: v})
		vertices = append(vertices, PrimitiveRoadVertex{Position: right, Normal: voplay.Vec3{Y: 1}, U: 1, V: v})
	}
	for i := 0; i < sampleCount; i++ {
		base := i * 2
		indices = append(indices, base, base + 1, base + 2, base + 1, base + 3, base + 2)
	}
	return buildPrimitiveRoadGLB(name, vertices, indices, color, roughness)
}

func buildPrimitiveTrackEdgeLinesGLB(track *scene3d.Track, sampleCount int, height float64, color voplay.Color, roughness float64, name string) []byte {
	vertices := []PrimitiveRoadVertex{}
	indices := []int{}
	appendEdgeLine := func(side float64) {
		startVertex := len(vertices)
		length := track.Length()
		for i := 0; i <= sampleCount; i++ {
			d := float64(i) / float64(sampleCount) * length
			if i == sampleCount {
				d = 0
			}
			pose := track.PoseAt(d)
			inner := pose.HalfWidth - 0.88
			outer := pose.HalfWidth - 0.62
			low := -outer
			high := -inner
			if side > 0 {
				low = inner
				high = outer
			}
			p0 := pose.Position.Add(pose.Right.Scale(low)).Add(voplay.Vec3{Y: height})
			p1 := pose.Position.Add(pose.Right.Scale(high)).Add(voplay.Vec3{Y: height})
			v := d / 18.0
			vertices = append(vertices, PrimitiveRoadVertex{Position: p0, Normal: voplay.Vec3{Y: 1}, U: 0, V: v})
			vertices = append(vertices, PrimitiveRoadVertex{Position: p1, Normal: voplay.Vec3{Y: 1}, U: 1, V: v})
		}
		for i := 0; i < sampleCount; i++ {
			base := startVertex + i * 2
			indices = append(indices, base, base + 1, base + 2, base + 1, base + 3, base + 2)
		}
	}
	appendEdgeLine(-1)
	appendEdgeLine(1)
	return buildPrimitiveRoadGLB(name, vertices, indices, color, roughness)
}

func buildPrimitiveTrackCenterDashesGLB(track *scene3d.Track, sampleCount int, height float64, color voplay.Color, roughness float64, name string) []byte {
	vertices := []PrimitiveRoadVertex{}
	indices := []int{}
	length := track.Length()
	step := length / float64(sampleCount)
	dashWidth := 0.32
	for i := 0; i < sampleCount; i += 4 {
		d0 := float64(i) * step + step * 0.24
		d1 := float64(i) * step + step * 1.35
		if d1 > length {
			d1 = length
		}
		p0 := track.PoseAt(d0)
		p1 := track.PoseAt(d1)
		base := len(vertices)
		vertices = append(vertices, PrimitiveRoadVertex{Position: p0.Position.Sub(p0.Right.Scale(dashWidth * 0.5)).Add(voplay.Vec3{Y: height}), Normal: voplay.Vec3{Y: 1}, U: 0, V: d0 / 18.0}, PrimitiveRoadVertex{Position: p0.Position.Add(p0.Right.Scale(dashWidth * 0.5)).Add(voplay.Vec3{Y: height}), Normal: voplay.Vec3{Y: 1}, U: 1, V: d0 / 18.0}, PrimitiveRoadVertex{Position: p1.Position.Sub(p1.Right.Scale(dashWidth * 0.5)).Add(voplay.Vec3{Y: height}), Normal: voplay.Vec3{Y: 1}, U: 0, V: d1 / 18.0}, PrimitiveRoadVertex{Position: p1.Position.Add(p1.Right.Scale(dashWidth * 0.5)).Add(voplay.Vec3{Y: height}), Normal: voplay.Vec3{Y: 1}, U: 1, V: d1 / 18.0})
		indices = append(indices, base, base + 1, base + 2, base + 1, base + 3, base + 2)
	}
	return buildPrimitiveRoadGLB(name, vertices, indices, color, roughness)
}

func buildPrimitiveTrackGrooveGLB(track *scene3d.Track, sampleCount int, height float64, color voplay.Color, roughness float64, name string) []byte {
	vertices := []PrimitiveRoadVertex{}
	indices := []int{}
	length := track.Length()
	step := length / float64(sampleCount)
	for i := 1; i < sampleCount; i += 6 {
		d := float64(i) * step
		pose := track.PoseAt(d)
		width := pose.HalfWidth * 2 - 2.25
		depth := 0.08
		base := len(vertices)
		center := pose.Position.Add(voplay.Vec3{Y: height})
		vertices = append(vertices, PrimitiveRoadVertex{Position: center.Sub(pose.Right.Scale(width * 0.5)).Sub(pose.Forward.Scale(depth * 0.5)), Normal: voplay.Vec3{Y: 1}, U: 0, V: 0}, PrimitiveRoadVertex{Position: center.Add(pose.Right.Scale(width * 0.5)).Sub(pose.Forward.Scale(depth * 0.5)), Normal: voplay.Vec3{Y: 1}, U: 1, V: 0}, PrimitiveRoadVertex{Position: center.Sub(pose.Right.Scale(width * 0.5)).Add(pose.Forward.Scale(depth * 0.5)), Normal: voplay.Vec3{Y: 1}, U: 0, V: 1}, PrimitiveRoadVertex{Position: center.Add(pose.Right.Scale(width * 0.5)).Add(pose.Forward.Scale(depth * 0.5)), Normal: voplay.Vec3{Y: 1}, U: 1, V: 1})
		indices = append(indices, base, base + 1, base + 2, base + 1, base + 3, base + 2)
	}
	return buildPrimitiveRoadGLB(name, vertices, indices, color, roughness)
}

func buildPrimitiveRoadGLB(name string, vertices []PrimitiveRoadVertex, indices []int, color voplay.Color, roughness float64) []byte {
	if len(vertices) == 0 || len(indices) == 0 {
		return nil
	}
	posOffset := 0
	normalOffset := len(vertices) * 12
	uvOffset := normalOffset + len(vertices) * 12
	indexOffset := uvOffset + len(vertices) * 8
	binLen := indexOffset + len(indices) * 4
	min := vertices[0].Position
	max := vertices[0].Position
	bin := newPrimitiveRoadWriter(binLen)
	for _, vertex := range vertices {
		min = primitiveRoadMinVec(min, vertex.Position)
		max = primitiveRoadMaxVec(max, vertex.Position)
		bin.WriteF32(vertex.Position.X)
		bin.WriteF32(vertex.Position.Y)
		bin.WriteF32(vertex.Position.Z)
	}
	for _, vertex := range vertices {
		bin.WriteF32(vertex.Normal.X)
		bin.WriteF32(vertex.Normal.Y)
		bin.WriteF32(vertex.Normal.Z)
	}
	for _, vertex := range vertices {
		bin.WriteF32(vertex.U)
		bin.WriteF32(vertex.V)
	}
	for _, index := range indices {
		bin.WriteU32(index)
	}
	json := primitiveRoadGLBJSON(name, len(vertices), len(indices), posOffset, normalOffset, uvOffset, indexOffset, binLen, min, max, color, roughness)
	jsonBytes := []byte(json)
	for len(jsonBytes) % 4 != 0 {
		jsonBytes = append(jsonBytes, byte(0x20))
	}
	binBytes := bin.Bytes()
	for len(binBytes) % 4 != 0 {
		binBytes = append(binBytes, byte(0))
	}
	totalLen := 12 + 8 + len(jsonBytes) + 8 + len(binBytes)
	out := newPrimitiveRoadWriter(totalLen)
	out.WriteRawBytes([]byte("glTF"))
	out.WriteU32(2)
	out.WriteU32(totalLen)
	out.WriteU32(len(jsonBytes))
	out.WriteRawBytes([]byte("JSON"))
	out.WriteRawBytes(jsonBytes)
	out.WriteU32(len(binBytes))
	out.WriteByte(byte(0x42))
	out.WriteByte(byte(0x49))
	out.WriteByte(byte(0x4e))
	out.WriteByte(byte(0x00))
	out.WriteRawBytes(binBytes)
	return out.Bytes()
}

func newPrimitiveRoadWriter(capacity int) primitiveRoadWriter {
	return primitiveRoadWriter{buf: make([]byte, 0, capacity)}
}

func (w *primitiveRoadWriter) Bytes() []byte {
	return w.buf
}

func (w *primitiveRoadWriter) WriteByte(v byte) {
	w.buf = append(w.buf, v)
}

func (w *primitiveRoadWriter) WriteU32(v int) {
	w.buf = append(w.buf, byte(v), byte(v >> 8), byte(v >> 16), byte(v >> 24))
}

func (w *primitiveRoadWriter) WriteF32(v float64) {
	b := math.Float32bits(float32(v))
	w.buf = append(w.buf, byte(b), byte(b >> 8), byte(b >> 16), byte(b >> 24))
}

func (w *primitiveRoadWriter) WriteRawBytes(data []byte) {
	w.buf = append(w.buf, data...)
}

func primitiveRoadGLBJSON(name string, vertexCount, indexCount, posOffset, normalOffset, uvOffset, indexOffset, binLen int, min, max voplay.Vec3, color voplay.Color, roughness float64) string {
	return "{" + "\"asset\":{\"version\":\"2.0\",\"generator\":\"BlockKart primitive road\"}," + "\"scene\":0,\"scenes\":[{\"nodes\":[0]}]," + "\"nodes\":[{\"mesh\":0,\"name\":\"" + name + "\"}]," + "\"meshes\":[{\"name\":\"" + name + "\",\"primitives\":[{\"attributes\":{\"POSITION\":0,\"NORMAL\":1,\"TEXCOORD_0\":2},\"indices\":3,\"material\":0}]}]," + "\"materials\":[{\"name\":\"" + name + "_material\",\"pbrMetallicRoughness\":{\"baseColorFactor\":[" + primitiveRoadFloat(color.R) + "," + primitiveRoadFloat(color.G) + "," + primitiveRoadFloat(color.B) + "," + primitiveRoadFloat(color.A) + "],\"roughnessFactor\":" + primitiveRoadFloat(roughness) + ",\"metallicFactor\":0}}]," + "\"buffers\":[{\"byteLength\":" + strconv.Itoa(binLen) + "}]," + "\"bufferViews\":[" + "{\"buffer\":0,\"byteOffset\":" + strconv.Itoa(posOffset) + ",\"byteLength\":" + strconv.Itoa(vertexCount * 12) + ",\"target\":34962}," + "{\"buffer\":0,\"byteOffset\":" + strconv.Itoa(normalOffset) + ",\"byteLength\":" + strconv.Itoa(vertexCount * 12) + ",\"target\":34962}," + "{\"buffer\":0,\"byteOffset\":" + strconv.Itoa(uvOffset) + ",\"byteLength\":" + strconv.Itoa(vertexCount * 8) + ",\"target\":34962}," + "{\"buffer\":0,\"byteOffset\":" + strconv.Itoa(indexOffset) + ",\"byteLength\":" + strconv.Itoa(indexCount * 4) + ",\"target\":34963}" + "]," + "\"accessors\":[" + "{\"bufferView\":0,\"componentType\":5126,\"count\":" + strconv.Itoa(vertexCount) + ",\"type\":\"VEC3\",\"min\":[" + primitiveRoadFloat(min.X) + "," + primitiveRoadFloat(min.Y) + "," + primitiveRoadFloat(min.Z) + "],\"max\":[" + primitiveRoadFloat(max.X) + "," + primitiveRoadFloat(max.Y) + "," + primitiveRoadFloat(max.Z) + "]}," + "{\"bufferView\":1,\"componentType\":5126,\"count\":" + strconv.Itoa(vertexCount) + ",\"type\":\"VEC3\"}," + "{\"bufferView\":2,\"componentType\":5126,\"count\":" + strconv.Itoa(vertexCount) + ",\"type\":\"VEC2\"}," + "{\"bufferView\":3,\"componentType\":5125,\"count\":" + strconv.Itoa(indexCount) + ",\"type\":\"SCALAR\"}" + "]" + "}"
}

func primitiveRoadFloat(value float64) string {
	return strconv.FormatFloat(value, 'f', 4, 64)
}

func primitiveRoadMinVec(a, b voplay.Vec3) voplay.Vec3 {
	return voplay.Vec3{X: math.Min(a.X, b.X), Y: math.Min(a.Y, b.Y), Z: math.Min(a.Z, b.Z)}
}

func primitiveRoadMaxVec(a, b voplay.Vec3) voplay.Vec3 {
	return voplay.Vec3{X: math.Max(a.X, b.X), Y: math.Max(a.Y, b.Y), Z: math.Max(a.Z, b.Z)}
}

func (w *World) addPrimitiveLandmarks(track *scene3d.Track) {
	w.addPrimitiveLakeAndBridge(track)
	w.addPrimitiveWaterfall()
	w.addPrimitiveMountainRange()
	w.addPrimitiveHillTower(track.PoseAt(track.Length() * 0.30))
	w.addPrimitiveTunnelPortal(track.PoseAt(track.Length() * 0.64))
}

func (w *World) addPrimitiveLakeAndBridge(track *scene3d.Track) {
	primitive := w.ensurePrimitiveScene()
	lake := primitiveSceneryVec3(44, -0.30, 8)
	primitive.AddStatic(primitive.RoundedBox, primitive.WaterMat, lake, voplay.QuatIdentity(), primitiveLandmarkVec3(62, 0.12, 39), voplay.Color{})
	for i := 0; i < 12; i++ {
		a := float64(i) / 12.0 * math.Pi * 2
		x := lake.X + math.Cos(a) * 33.0 * primitiveLandmarkScale
		z := lake.Z + math.Sin(a) * 21.0 * primitiveLandmarkScale
		scale := 1.2 + float64(i % 4) * 0.16
		primitive.AddStatic(primitive.RoundedBox, primitive.StoneMat, voplay.Vec3{X: x, Y: 0.12, Z: z}, voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, a), primitiveLandmarkVec3(2.2 * scale, 0.54, 1.45 * scale), voplay.Color{})
	}
	w.addPrimitiveStoneBridge(track.PoseAt(track.Length() * 0.46))
}

func (w *World) addPrimitiveStoneBridge(pose scene3d.TrackPose) {
	primitive := w.ensurePrimitiveScene()
	deckPos := pose.Position.Add(voplay.Vec3{Y: -0.10})
	primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, deckPos, pose.Rotation, voplay.Vec3{X: pose.HalfWidth * 2 + 4.0, Y: 0.72, Z: 8.6}, voplay.Color{})
	for i := -2; i <= 2; i++ {
		lateral := float64(i) * 4.6
		col := deckPos.Add(pose.Right.Scale(lateral)).Add(voplay.Vec3{Y: -1.55})
		primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, col, pose.Rotation, voplay.Vec3{X: 1.25, Y: 2.9, Z: 1.2}, voplay.Color{})
		if i < 2 {
			archCenter := deckPos.Add(pose.Right.Scale(lateral + 2.3)).Add(voplay.Vec3{Y: -0.55})
			primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, archCenter, pose.Rotation, voplay.Vec3{X: 2.7, Y: 0.55, Z: 1.1}, voplay.Color{})
		}
	}
	railY := deckPos.Add(voplay.Vec3{Y: 1.0})
	primitive.AddStatic(primitive.RoundedBox, primitive.WoodMat, railY.Add(pose.Right.Scale(pose.HalfWidth + 1.8)), pose.Rotation, voplay.Vec3{X: 0.26, Y: 0.22, Z: 9.2}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.WoodMat, railY.Sub(pose.Right.Scale(pose.HalfWidth + 1.8)), pose.Rotation, voplay.Vec3{X: 0.26, Y: 0.22, Z: 9.2}, voplay.Color{})
}

func (w *World) addPrimitiveWaterfall() {
	primitive := w.ensurePrimitiveScene()
	base := primitiveSceneryVec3(-96, 0, -24)
	primitive.AddStatic(primitive.RoundedBox, primitive.CliffMat, base.Add(primitiveLandmarkVec3(0, 2.2, 0)), voplay.QuatIdentity(), primitiveLandmarkVec3(34, 4.8, 17), voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.GrassMat, base.Add(primitiveLandmarkVec3(0, 4.95, -0.4)), voplay.QuatIdentity(), primitiveLandmarkVec3(36, 0.52, 18), voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.CliffMat, base.Add(primitiveLandmarkVec3(-8, 6.5, -3)), voplay.QuatIdentity(), primitiveLandmarkVec3(16, 3.1, 10), voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.MeadowMat, base.Add(primitiveLandmarkVec3(-8, 8.25, -3)), voplay.QuatIdentity(), primitiveLandmarkVec3(17, 0.46, 11), voplay.Color{})
	for i := 0; i < 5; i++ {
		x := base.X + (-7.5 + float64(i) * 3.4) * primitiveLandmarkScale
		primitive.AddStatic(primitive.RoundedBox, primitive.WaterMat, voplay.Vec3{X: x, Y: 4.3 * primitiveLandmarkScale, Z: base.Z + 8.55 * primitiveLandmarkScale}, voplay.QuatIdentity(), primitiveLandmarkVec3(2.4, 7.8, 0.45), voplay.Color{})
	}
	primitive.AddStatic(primitive.RoundedBox, primitive.WaterMat, base.Add(primitiveLandmarkVec3(0, -0.22, 17)), voplay.QuatIdentity(), primitiveLandmarkVec3(38, 0.12, 20), voplay.Color{})
	for i := 0; i < 7; i++ {
		w.addPrimitiveTreeAtWorld(base.Add(primitiveLandmarkVec3(-14 + float64(i) * 4.8, 8.5, -9 + float64((i * 5) % 7))), (0.78 + float64(i % 3) * 0.08) * primitiveLandmarkScale)
	}
}

func (w *World) addPrimitiveMountainRange() {
	primitive := w.ensurePrimitiveScene()
	for i := 0; i < 8; i++ {
		x := (-126.0 + float64(i) * 36.0) * primitiveMapPlanarScale
		z := (-148.0 - float64((i * 13) % 24)) * primitiveMapPlanarScale
		h := (6.5 + float64((i * 7) % 5)) * primitiveLandmarkScale
		rot := voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, float64(i) * 0.21)
		primitive.AddStatic(primitive.RoundedBox, primitive.CliffMat, voplay.Vec3{X: x, Y: h * 0.25, Z: z}, rot, primitiveLandmarkVec3(24, h * 0.55 / primitiveLandmarkScale, 16), voplay.Color{})
		primitive.AddStatic(primitive.RoundedBox, primitive.MeadowMat, voplay.Vec3{X: x + 1.5 * primitiveLandmarkScale, Y: h * 0.55, Z: z - 0.5 * primitiveLandmarkScale}, rot, primitiveLandmarkVec3(21, 0.9, 14), voplay.Color{})
		primitive.AddStatic(primitive.Cone, primitive.PaleStoneMat, voplay.Vec3{X: x + 3 * primitiveLandmarkScale, Y: h + 1.4 * primitiveLandmarkScale, Z: z}, voplay.QuatIdentity(), primitiveLandmarkVec3(13, 9.4, 13), voplay.Color{})
	}
}

func (w *World) addPrimitiveHillTower(pose scene3d.TrackPose) {
	primitive := w.ensurePrimitiveScene()
	base := pose.Position.Add(pose.Right.Scale(pose.HalfWidth + 54)).Add(voplay.Vec3{Y: 0.4})
	primitive.AddStatic(primitive.RoundedBox, primitive.CliffMat, base.Add(voplay.Vec3{Y: 2.0}), voplay.QuatIdentity(), voplay.Vec3{X: 34, Y: 4.2, Z: 28}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.GrassMat, base.Add(voplay.Vec3{Y: 4.45}), voplay.QuatIdentity(), voplay.Vec3{X: 36, Y: 0.58, Z: 30}, voplay.Color{})
	tower := base.Add(voplay.Vec3{Y: 5.2})
	primitive.AddStatic(primitive.Cylinder, primitive.TowerWallMat, tower.Add(voplay.Vec3{Y: 3.0}), voplay.QuatIdentity(), voplay.Vec3{X: 4.8, Y: 6.0, Z: 4.8}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.TowerWallMat, tower.Add(voplay.Vec3{Y: 6.55}), voplay.QuatIdentity(), voplay.Vec3{X: 7.2, Y: 1.3, Z: 7.2}, voplay.Color{})
	primitive.AddStatic(primitive.Cone, primitive.TowerRoofMat, tower.Add(voplay.Vec3{Y: 8.2}), voplay.QuatIdentity(), voplay.Vec3{X: 8.2, Y: 3.2, Z: 8.2}, voplay.Color{})
	for i := 0; i < 8; i++ {
		a := float64(i) / 8.0 * math.Pi * 2
		post := tower.Add(voplay.Vec3{X: math.Cos(a) * 11.5, Y: 5.55, Z: math.Sin(a) * 9.0})
		primitive.AddStatic(primitive.Cylinder, primitive.WoodMat, post, voplay.QuatIdentity(), voplay.Vec3{X: 0.24, Y: 1.15, Z: 0.24}, voplay.Color{})
	}
	w.addPrimitiveTreeAtWorld(base.Add(voplay.Vec3{X: -13, Y: 4.85, Z: -7}), 0.88)
	w.addPrimitiveTreeAtWorld(base.Add(voplay.Vec3{X: 13, Y: 4.85, Z: 8}), 0.82)
}

func (w *World) addPrimitiveTunnelPortal(pose scene3d.TrackPose) {
	primitive := w.ensurePrimitiveScene()
	center := pose.Position.Add(voplay.Vec3{Y: 2.0})
	primitive.AddStatic(primitive.RoundedBox, primitive.CliffMat, center.Add(voplay.Vec3{Y: 1.6}), pose.Rotation, voplay.Vec3{X: pose.HalfWidth * 2 + 12, Y: 7.6, Z: 8.5}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.RoadMat, center.Add(voplay.Vec3{Y: -1.25}), pose.Rotation, voplay.Vec3{X: pose.HalfWidth * 2 + 2.0, Y: 3.9, Z: 9.0}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, center.Add(pose.Right.Scale(-(pose.HalfWidth + 1.4))), pose.Rotation, voplay.Vec3{X: 2.0, Y: 5.6, Z: 9.6}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, center.Add(pose.Right.Scale(pose.HalfWidth + 1.4)), pose.Rotation, voplay.Vec3{X: 2.0, Y: 5.6, Z: 9.6}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.PaleStoneMat, center.Add(voplay.Vec3{Y: 3.2}), pose.Rotation, voplay.Vec3{X: pose.HalfWidth * 2 + 6.0, Y: 1.7, Z: 9.7}, voplay.Color{})
	primitive.AddStatic(primitive.Sphere, primitive.GlowMat, center.Add(pose.Right.Scale(-pose.HalfWidth * 0.62)).Add(voplay.Vec3{Y: 0.15}), pose.Rotation, voplay.Vec3{X: 0.6, Y: 0.6, Z: 0.6}, voplay.Color{})
	primitive.AddStatic(primitive.Sphere, primitive.GlowMat, center.Add(pose.Right.Scale(pose.HalfWidth * 0.62)).Add(voplay.Vec3{Y: 0.15}), pose.Rotation, voplay.Vec3{X: 0.6, Y: 0.6, Z: 0.6}, voplay.Color{})
}

func (w *World) addPrimitiveFencePair(pose scene3d.TrackPose, step float64) {
	primitive := w.ensurePrimitiveScene()
	for _, side := range []float64{-1, 1} {
		base := pose.Position.Add(pose.Right.Scale(side * (pose.HalfWidth + 3.0)))
		postRot := voplay.QuatIdentity()
		primitive.AddStatic(primitive.Cylinder, primitive.WoodMat, base.Add(voplay.Vec3{Y: 0.78}), postRot, voplay.Vec3{X: 0.24, Y: 1.55, Z: 0.24}, voplay.Color{})
