func (w *World) addPrimitiveClouds() {
	primitive := w.ensurePrimitiveScene()
	for i := 0; i < 12; i++ {
		x := -142.0 + float64(i % 6) * 58.0
		z := -118.0 + float64(i / 6) * 72.0 + float64((i * 13) % 17)
		y := 42.0 + float64((i * 7) % 9)
		base := primitiveSceneryVec3(x, y, z)
		primitive.AddStatic(primitive.Sphere, primitive.CloudMat, base, voplay.QuatIdentity(), primitiveLandmarkVec3(8.0, 5.2, 6.4), voplay.Color{})
		primitive.AddStatic(primitive.Sphere, primitive.CloudShadowMat, base.Add(primitiveLandmarkVec3(-5.2, -1.1, 1.6)), voplay.QuatIdentity(), primitiveLandmarkVec3(5.0, 3.2, 4.2), voplay.Color{})
