func (w *World) spawnPrimitiveTrackPhysics(track *scene3d.Track) {
	length := track.Length()
	count := primitiveTrackSampleCount(track)
	step := length / float64(count)
	ground := w.scene.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Y: primitiveTerrainY + 1.42}, Tag: "primitive_ground_physics", Physics: &scene3d.Physics{Type: scene3d.Static, Collider: scene3d.Box(primitiveTerrainWidth * 0.5, 0.18, primitiveTerrainDepth * 0.5), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll, Friction: 0.72, Restitution: 0.02}, PickMode: scene3d.PickDisabled})
	ground.Visible = false
	w.trackResult.Entities = append(w.trackResult.Entities, ground)
	if w.spawnPrimitiveRoadCollisionMesh(track, count) {
		return
	}
	w.spawnPrimitiveRoadBoxPhysics(track, count, step)
}

func (w *World) spawnPrimitiveRoadCollisionMesh(track *scene3d.Track, count int) bool {
	return false
}

func (w *World) spawnPrimitiveRoadBoxPhysics(track *scene3d.Track, count int, step float64) {
	for i := 0; i < count; i++ {
		pose := track.PoseAt(float64(i) * step + step * 0.5)
		ent := w.scene.Spawn(scene3d.EntityDesc{Position: pose.Position.Add(voplay.Vec3{Y: -0.08}), Rotation: pose.Rotation, Tag: "primitive_road_physics", Physics: &scene3d.Physics{Type: scene3d.Static, Collider: scene3d.Box(pose.HalfWidth + 1.1, 0.18, step * 0.58), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll, Friction: 1.05, Restitution: 0.01}, PickMode: scene3d.PickDisabled})
		ent.Visible = false
		w.trackResult.Entities = append(w.trackResult.Entities, ent)
	}
}

func (w *World) spawnPrimitiveGameplay(track *scene3d.Track) {
	length := track.Length()
	for i := 0; i < 8; i++ {
		d := length * (0.08 + float64(i) * 0.105)
		pose := track.PoseAt(d)
		w.addCollectible(pose.Position.Add(voplay.Vec3{Y: 2.1}), "primitive_collectible_" + itoa(i))
	}
	for _, d := range []float64{length * 0.13, length * 0.59} {
		pose := track.PoseAt(d)
		w.addBoostPad(pose.Position, 7.0)
		w.addPrimitiveBoostPadVisual(pose)
	}
}

func (w *World) addPrimitiveBoostPadVisual(pose scene3d.TrackPose) {
	primitive := w.ensurePrimitiveScene()
	primitive.AddStatic(primitive.RoundedBox, primitive.BoostMat, pose.Position.Add(voplay.Vec3{Y: 0.22}), pose.Rotation, voplay.Vec3{X: 6.2, Y: 0.12, Z: 3.2}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.GlowMat, pose.Position.Add(voplay.Vec3{Y: 0.32}).Add(pose.Right.Scale(-2.2)), pose.Rotation, voplay.Vec3{X: 0.38, Y: 0.08, Z: 2.65}, voplay.Color{})
	primitive.AddStatic(primitive.RoundedBox, primitive.GlowMat, pose.Position.Add(voplay.Vec3{Y: 0.32}).Add(pose.Right.Scale(2.2)), pose.Rotation, voplay.Vec3{X: 0.38, Y: 0.08, Z: 2.65}, voplay.Color{})
}

func primitiveTrackSampleCount(track *scene3d.Track) int {
	count := int(math.Ceil(track.Length() / primitiveTrackSegmentLength))
	if count < 24 {
		count = 24
	}
	return count
}

