func (w *World) syncPrimitiveKartVisuals(pos voplay.Vec3, rot voplay.Quat) {
	for _, part := range w.kartBodyPrimitiveParts {
		w.syncPrimitiveKartBodyPart(part, pos, rot)
	}
	boostVisible := w.isBoosting()
	if w.kartFlameLeftPrimitive != nil {
		w.kartFlameLeftPrimitive.SetVisible(boostVisible)
	}
	if w.kartFlameRightPrimitive != nil {
		w.kartFlameRightPrimitive.SetVisible(boostVisible)
	}
	if len(w.kartWheelVisuals) > 0 {
		for _, wheel := range w.kartWheelVisuals {
			w.syncPrimitiveKartWheelVisual(wheel, pos, rot)
		}
		return
	}
	if len(w.kartWheelPrimitives) >= 4 {
		w.syncPrimitiveKartWheel(w.kartWheelPrimitives[0], pos, rot, voplay.Vec3{X: -1.04, Y: 0.12, Z: -0.80}, true, 0)
		w.syncPrimitiveKartWheel(w.kartWheelPrimitives[1], pos, rot, voplay.Vec3{X: 1.04, Y: 0.12, Z: -0.80}, true, 1)
		w.syncPrimitiveKartWheel(w.kartWheelPrimitives[2], pos, rot, voplay.Vec3{X: -1.04, Y: 0.12, Z: 0.84}, false, 2)
		w.syncPrimitiveKartWheel(w.kartWheelPrimitives[3], pos, rot, voplay.Vec3{X: 1.04, Y: 0.12, Z: 0.84}, false, 3)
	}
}

func (w *World) addPrimitiveKartBodyPart(primitive *BlockKartPrimitiveScene, pos voplay.Vec3, rot voplay.Quat, shape primitive3d.ShapeID, material primitive3d.MaterialID, local voplay.Vec3, localRot voplay.Quat, scale voplay.Vec3, tint voplay.Color) *PrimitivePart {
	local = primitiveKartScaleVec(local)
	scale = primitiveKartScaleVec(scale)
	part := primitive.AddDynamic(shape, material, pos.Add(rot.RotateVec3(local)), rot.Mul(localRot), scale, tint)
	w.kartBodyPrimitiveParts = append(w.kartBodyPrimitiveParts, PrimitiveKartBodyPart{Part: part, Local: local, LocalRotation: localRot})
	return part
}

func (w *World) addPrimitiveKartWheelVisual(primitive *BlockKartPrimitiveScene, pos voplay.Vec3, rot voplay.Quat, local voplay.Vec3, steer bool, wheelIndex int, sideSign float64) {
	if sideSign == 0 {
		sideSign = 1
		if local.X < 0 {
			sideSign = -1
		}
	}
	local = primitiveKartScaleVec(local)
	wheelPos := pos.Add(rot.RotateVec3(local))
	axisRot := voplay.QuatFromAxisAngle(voplay.Vec3{Z: 1}, math.Pi * 0.5)
	wheelRot := rot.Mul(axisRot)
	tire := primitive.AddDynamic(primitive.Cylinder, primitive.WheelMat, wheelPos, wheelRot, primitiveKartScaleVec(voplay.Vec3{X: 0.64, Y: 0.42, Z: 0.64}), voplay.Color{})
	rim := primitive.AddDynamic(primitive.Cylinder, primitive.MetalMat, wheelPos, wheelRot, primitiveKartScaleVec(voplay.Vec3{X: 0.34, Y: 0.055, Z: 0.34}), voplay.Color{})
	hub := primitive.AddDynamic(primitive.Cylinder, primitive.WhiteMat, wheelPos, wheelRot, primitiveKartScaleVec(voplay.Vec3{X: 0.18, Y: 0.07, Z: 0.18}), voplay.Color{})
	stripe := primitive.AddDynamic(primitive.RoundedBox, primitive.OrangeTrimMat, wheelPos, wheelRot, primitiveKartScaleVec(voplay.Vec3{X: 0.032, Y: 0.06, Z: 0.20}), voplay.Color{})
	w.kartWheelPrimitives = append(w.kartWheelPrimitives, tire)
	w.kartWheelVisuals = append(w.kartWheelVisuals, PrimitiveKartWheelVisual{Tire: tire, Rim: rim, Hub: hub, Stripe: stripe, Local: local, Steer: steer, WheelIndex: wheelIndex, SideSign: sideSign})
}

func (w *World) syncPrimitiveKartBodyPart(body PrimitiveKartBodyPart, pos voplay.Vec3, rot voplay.Quat) {
	if body.Part == nil {
		return
	}
	body.Part.SetPose(pos.Add(rot.RotateVec3(body.Local)), rot.Mul(body.LocalRotation))
}

func (w *World) syncPrimitiveKartPart(part *PrimitivePart, pos voplay.Vec3, rot voplay.Quat, local voplay.Vec3, partRot voplay.Quat) {
	if part == nil {
		return
	}
	part.SetPose(pos.Add(rot.RotateVec3(local)), partRot)
}

func (w *World) syncPrimitiveKartWheelVisual(wheel PrimitiveKartWheelVisual, pos voplay.Vec3, rot voplay.Quat) {
	if wheel.Tire == nil {
		return
	}
	wheelRot := rot
	wheelPos := pos.Add(rot.RotateVec3(wheel.Local))
	if w.vehicle != nil {
		steerAngle := w.vehicle.SteerAngle
		spin := w.vehicle.WheelSpin
		if state, ok := w.vehicle.WheelState(wheel.WheelIndex); ok {
			steerAngle = state.Steering
			spin = state.Rotation
		}
		if wheel.Steer {
			wheelRot = wheelRot.Mul(voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, -steerAngle))
		}
		wheelRot = wheelRot.Mul(voplay.QuatFromAxisAngle(voplay.Vec3{X: 1}, spin))
	}
	axisRot := voplay.QuatFromAxisAngle(voplay.Vec3{Z: 1}, math.Pi * 0.5)
	cylinderRot := wheelRot.Mul(axisRot)
	wheel.Tire.SetPose(wheelPos, cylinderRot)
	sideDir := wheelRot.RotateVec3(voplay.Vec3{X: wheel.SideSign})
	facePos := wheelPos.Add(sideDir.Scale(0.29 * primitiveKartVisualScale))
	if wheel.Rim != nil {
		wheel.Rim.SetPose(facePos, cylinderRot)
	}
	if wheel.Hub != nil {
		wheel.Hub.SetPose(facePos.Add(sideDir.Scale(0.035 * primitiveKartVisualScale)), cylinderRot)
	}
	if wheel.Stripe != nil {
		radial := wheelRot.RotateVec3(voplay.Vec3{Y: 0.17 * primitiveKartVisualScale})
		wheel.Stripe.SetPose(facePos.Add(sideDir.Scale(0.012 * primitiveKartVisualScale)).Add(radial), wheelRot)
	}
}

func primitiveKartScaleVec(v voplay.Vec3) voplay.Vec3 {
	return voplay.Vec3{X: v.X * primitiveKartVisualScale, Y: v.Y * primitiveKartVisualScale, Z: v.Z * primitiveKartVisualScale}
}

func (w *World) syncPrimitiveKartWheel(part *PrimitivePart, pos voplay.Vec3, rot voplay.Quat, local voplay.Vec3, steer bool, wheelIndex int) {
	if part == nil {
		return
	}
	wheelRot := rot
	wheelPos := pos.Add(rot.RotateVec3(local))
	if w.vehicle != nil {
		steerAngle := w.vehicle.SteerAngle
		spin := w.vehicle.WheelSpin
		if state, ok := w.vehicle.WheelState(wheelIndex); ok {
			wheelPos = state.Center
			steerAngle = state.Steering
			spin = state.Rotation
		}
		if steer {
			wheelRot = wheelRot.Mul(voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, -steerAngle))
		}
		wheelRot = wheelRot.Mul(voplay.QuatFromAxisAngle(voplay.Vec3{X: 1}, spin))
	}
	wheelRot = wheelRot.Mul(voplay.QuatFromAxisAngle(voplay.Vec3{Z: 1}, math.Pi * 0.5))
	part.SetPose(wheelPos, wheelRot)
}

func normalizePrimitiveQuat(rotation voplay.Quat) voplay.Quat {
	if rotation == (voplay.Quat{}) {
		return voplay.QuatIdentity()
	}
	return rotation
}

func normalizePrimitiveVecScale(scale voplay.Vec3) voplay.Vec3 {
	if scale == (voplay.Vec3{}) {
		return voplay.Vec3{X: 1, Y: 1, Z: 1}
	}
	return scale
}

