func drawWorldHUD(theme *WorldTheme, g *voplay.GameCtx, hud *WorldHUDState) {
	if voplay.IsCompactTouchLayout(g.Width, g.Height) {
		drawCompactWorldHUD(theme, g, hud)
		return
	}
	drawHudPanel(g.Draw, theme, 24, 22, 430, 112, 0.88)
	g.Draw.DrawRect(24, 22, 430, 10, theme.HudTrimColor)
	g.Draw.DrawText("BlockKart", 42, 58, 30, theme.HudTextColor)
	g.Draw.DrawText("Primitive Track", 42, 86, 20, theme.HudAccentTextColor)
	g.Draw.DrawText("Retained primitive render path", 42, 112, 18, theme.HudSubtextColor)
	courseX := float64(g.Width - 330 - 24)
	if courseX < 24 {
		courseX = 24
	}
	drawHudPanel(g.Draw, theme, courseX, 22, 330, 100, 0.86)
	g.Draw.DrawRect(courseX, 22, 330, 8, theme.GoalTrimColor)
