func drawHudPanel(d *voplay.DrawCtx, theme *WorldTheme, x, y, width, height float64, alpha float64) {
	d.DrawRect(x + 4, y + 5, width, height, theme.HudShadowColor.WithAlpha(0.18))
	d.DrawRect(x, y, width, height, theme.HudPanelColor.WithAlpha(alpha))
}

func formatTime(seconds float64) string {
	return fmt.Sprintf("%.1fs", seconds)
}

func formatHudFloat(value float64, digits int) string {
	if digits <= 1 {
		return fmt.Sprintf("%.1f", value)
	}
	return fmt.Sprintf("%.2f", value)
}

func formatHudMs(value float64) string {
	return fmt.Sprintf("%.2fms", value)
}

func formatHudBytes(value int) string {
	if value >= 1024 * 1024 {
		return fmt.Sprintf("%.2fMB", float64(value) / (1024.0 * 1024.0))
	}
	if value >= 1024 {
		return fmt.Sprintf("%.1fKB", float64(value) / 1024.0)
	}
	return itoa(value) + "B"
}

func boolHud(value bool) string {
	if value {
		return "yes"
	}
	return "no"
}

func renderDebugLabel(mode int) string {
	if mode == scene3d.RenderDebugAlbedo {
		return "Albedo"
	}
	if mode == scene3d.RenderDebugNormal {
		return "Normal"
	}
	if mode == scene3d.RenderDebugRoughness {
		return "Roughness"
	}
	if mode == scene3d.RenderDebugMetallic {
		return "Metallic"
	}
	if mode == scene3d.RenderDebugShadow {
		return "Shadow"
	}
	if mode == scene3d.RenderDebugDirect {
		return "Direct"
	}
	if mode == scene3d.RenderDebugAmbient {
		return "Ambient"
	}
	return "Lit"
}

